const raw = $input.first().json;
let data = raw;
if (raw.query && typeof raw.query === 'object' && !Array.isArray(raw.query)) {
  data = raw.query;
} else if (typeof raw.input === 'string') {
  try { data = JSON.parse(raw.input); } catch(e) {}
} else if (typeof raw.query === 'string') {
  try { data = JSON.parse(raw.query); } catch(e) {}
}
if (!data.employee) throw new Error('sc_progul_ochny: не переданы данные employee.');
if (!data.violation) throw new Error('sc_progul_ochny: не переданы данные violation.');
// Проставить scenario если не передан
data.scenario = data.scenario || 'progul_ochny';
return [{ json: { context: data } }];

const fs = require('fs');
const base = process.env.HR_KNOWLEDGE_DIR
  || '/Users/olegkluev/Documents/Projects/hr-consultant/knowledge';
const checklist = fs.readFileSync(`${base}/progul_checklist.md`, 'utf8');
const tk = fs.readFileSync(`${base}/progul_tk193.md`, 'utf8');
const d = $input.first().json;
return [{ json: { ...d, checklist_content: checklist, tk_content: tk } }];

// VISION STUB v1 — TODO: заменить на HTTP Request к vision-модели Ollama (qwen2-vl / llava)
// Интерфейс: принимает evidenceDescription, возвращает { vision_stub, analysis }
// При замене: убрать этот нод, добавить HTTP Request к http://127.0.0.1:11434/api/generate
// с моделью qwen2-vl и base64-изображением в поле images[]
const d = $input.first().json;
const desc = d.context?.evidenceDescription || 'Доказательства не предоставлены';
return [{ json: {
  ...d,
  vision_analysis: {
    vision_stub: true,
    analysis: desc,
    _note: 'STUB: заменить на реальную vision-модель'
  }
} }];

// Результат lib_rag приходит в $input.first().json
// Данные из предыдущих нодов нужно получить через $('Вызов lib_rag').first() — нет, только через merge
// Используем глобальный $('нод')  
const ragResult = $input.first().json;
const violations = ragResult.violations || '[Не удалось сформулировать нарушение]';
// Восстанавливаем полный контекст из предыдущего нода через $node
const prev = $('Vision: анализ доказательств (заглушка)').first().json;
return [{ json: {
  context: prev.context,
  checklist_content: prev.checklist_content,
  tk_content: prev.tk_content,
  vision_analysis: prev.vision_analysis,
  violations
} }];

const actResult = $input.first().json;
const act_text = actResult.act_text || '[Не удалось сгенерировать акт]';
const prev = $('Добавить violations в контекст').first().json;
return [{ json: {
  context: prev.context,
  violations: prev.violations,
  vision_analysis: prev.vision_analysis,
  act_text
} }];

const szResult = $input.first().json;
const sz_text = szResult.sz_text || '[Не удалось сгенерировать служебную записку]';
const prev = $('Добавить act_text в контекст').first().json;

const output = `✅ Документы сформированы!

---

📋 АКТ ОБ ОТСУТСТВИИ НА РАБОЧЕМ МЕСТЕ

${prev.act_text}

---

📝 СЛУЖЕБНАЯ ЗАПИСКА

${sz_text}

---

⚠️ Проверьте документы перед отправкой. Поля [УТОЧНИТЬ] требуют вашего заполнения.
После проверки — передайте пакет Черепановой Т. или Касмыниной О.`;

return [{ json: { output, act_text: prev.act_text, sz_text } }];
